&lt;/li&gt;
&lt;li class=&quot;public-DraftStyleDefault-unorderedListItem public-DraftStyleDefault-depth0 public-DraftStyleDefault-listLTR&quot; data-block=&quot;true&quot; data-editor=&quot;6euto&quot; data-offset-key=&quot;1l62q-0-0&quot;&gt;
